import{_ as a,o as e,c as r,ag as l}from"./chunks/framework.C6K0jwmI.js";const u=JSON.parse('{"title":"トラブルシューティング","description":"","frontmatter":{"title":"トラブルシューティング"},"headers":[],"relativePath":"tenant/19-troubleshoot.md","filePath":"tenant/19-troubleshoot.md"}'),d={name:"tenant/19-troubleshoot.md"};function o(i,t,n,h,s,c){return e(),r("div",null,[...t[0]||(t[0]=[l('<h1 id="_19-トラブルシューティング" tabindex="-1">19. トラブルシューティング <a class="header-anchor" href="#_19-トラブルシューティング" aria-label="Permalink to &quot;19. トラブルシューティング&quot;">​</a></h1><p>問題が起きたときは、画面名、操作内容、表示されたメッセージ、発生時刻を確認してください。POSLAサポートへ連絡する際にも、この情報があると確認が早くなります。</p><h2 id="まず確認すること" tabindex="-1">まず確認すること <a class="header-anchor" href="#まず確認すること" aria-label="Permalink to &quot;まず確認すること&quot;">​</a></h2><ol><li>インターネット接続を確認します。</li><li>ブラウザを再読み込みします。</li><li>別の端末またはブラウザで試します。</li><li>ログイン中のユーザーと権限を確認します。</li><li>店舗選択が正しいか確認します。</li></ol><h2 id="よくある症状" tabindex="-1">よくある症状 <a class="header-anchor" href="#よくある症状" aria-label="Permalink to &quot;よくある症状&quot;">​</a></h2><table tabindex="0"><thead><tr><th>症状</th><th>確認すること</th></tr></thead><tbody><tr><td>ログインできない</td><td>ユーザー名、パスワード、アカウント状態</td></tr><tr><td>注文が届かない</td><td>Wi-Fi、KDS画面、店舗・テーブル設定</td></tr><tr><td>会計できない</td><td>注文状態、支払い方法、PIN、決済端末</td></tr><tr><td>メニューが出ない</td><td>商品の販売状態、カテゴリ、店舗表示設定</td></tr><tr><td>QRコードが読めない</td><td>印刷状態、貼り間違い、テーブル開放状態</td></tr><tr><td>レポートが合わない</td><td>期間、営業日区切り、会計済み状態</td></tr><tr><td>画面に黄色いバナーで「古いデータを表示中」と出る</td><td>通信が一時的に切れています。<strong>操作は通信復帰後に行ってください</strong>。詳細は『KDS デバイスガイド』「通信が一時的に切れた場合の挙動」</td></tr></tbody></table><h2 id="poslaサポートへ連絡する前に" tabindex="-1">POSLAサポートへ連絡する前に <a class="header-anchor" href="#poslaサポートへ連絡する前に" aria-label="Permalink to &quot;POSLAサポートへ連絡する前に&quot;">​</a></h2><p>以下を控えてください。</p><ul><li>店舗名</li><li>操作した画面</li><li>操作したユーザー名</li><li>発生日時</li><li>表示されたメッセージ</li><li>可能であればスクリーンショット</li></ul><h2 id="緊急時の考え方" tabindex="-1">緊急時の考え方 <a class="header-anchor" href="#緊急時の考え方" aria-label="Permalink to &quot;緊急時の考え方&quot;">​</a></h2><p>営業中に注文や会計が止まる場合は、まず店舗の代替運用に切り替えてください。紙伝票、手書き会計、手動レジ締めなどの緊急対応を行い、営業後にPOSLAサポートへ状況をご共有ください。</p><h2 id="困ったとき" tabindex="-1">困ったとき <a class="header-anchor" href="#困ったとき" aria-label="Permalink to &quot;困ったとき&quot;">​</a></h2><p>管理画面右下のAIヘルプデスクも利用できます。質問時は「どの画面で」「何をしたら」「どのメッセージが出たか」を入力してください。</p>',13)])])}const b=a(d,[["render",o]]);export{u as __pageData,b as default};
